import React, { useEffect, useRef, useState } from 'react';
import Quagga from 'quagga';
import './BarcodeScanner.css';

/**
 * FIXED Barcode Scanner Component
 * - Proper debouncing (1.5s)
 * - SKU normalization to uppercase string
 * - Mobile-safe configuration
 * - Clean start/stop lifecycle
 */
const BarcodeScanner = ({ onScan, onError }) => {
  const [isScanning, setIsScanning] = useState(false);
  const [lastScan, setLastScan] = useState(null);
  const scannerRef = useRef(null);
  const debounceTimerRef = useRef(null);

  const DEBOUNCE_DELAY = 1500; // 1.5 seconds

  useEffect(() => {
    return () => {
      stopScanning();
    };
  }, []);

  /**
   * Start Quagga scanner with mobile-safe config
   */
  const startScanning = () => {
    if (isScanning) return;

    const config = {
      inputStream: {
        name: 'Live',
        type: 'LiveStream',
        target: scannerRef.current,
        constraints: {
          facingMode: 'environment', // Back camera on mobile
          aspectRatio: { min: 1, max: 2 }
          // NO fixed width/height for mobile compatibility
        }
      },
      decoder: {
        readers: [
          'code_128_reader',
          'ean_reader',
          'ean_8_reader',
          'code_39_reader',
          'upc_reader',
          'upc_e_reader'
        ],
        multiple: false
      },
      locate: true,
      numOfWorkers: navigator.hardwareConcurrency || 2,
      frequency: 10
    };

    Quagga.init(config, (err) => {
      if (err) {
        console.error('Quagga init error:', err);
        onError?.('Failed to start camera: ' + (err.message || 'Unknown error'));
        return;
      }

      Quagga.start();
      setIsScanning(true);
    });

    Quagga.onDetected(handleDetected);
  };

  /**
   * Stop scanner and cleanup
   */
  const stopScanning = () => {
    if (isScanning) {
      Quagga.stop();
      Quagga.offDetected(handleDetected);
      setIsScanning(false);

      if (debounceTimerRef.current) {
        clearTimeout(debounceTimerRef.current);
      }
    }
  };

  /**
   * Handle barcode detection with debouncing
   * CRITICAL: Normalize SKU to uppercase string
   */
  const handleDetected = (result) => {
    if (!result || !result.codeResult) return;

    const rawCode = result.codeResult.code;
    const sku = String(rawCode).trim().toUpperCase(); // STRING + UPPERCASE

    // Prevent duplicate scans
    if (sku === lastScan) return;

    // Clear existing timer
    if (debounceTimerRef.current) {
      clearTimeout(debounceTimerRef.current);
    }

    // Set debounce timer
    debounceTimerRef.current = setTimeout(() => {
      setLastScan(sku);
      onScan?.(sku);

      // Clear last scan after delay to allow re-scanning
      setTimeout(() => setLastScan(null), DEBOUNCE_DELAY);
    }, 300);
  };

  return (
    <div className="barcode-scanner">
      <div className="scanner-header">
        <h3>Scan Barcode</h3>
      </div>

      <div className="scanner-viewport" ref={scannerRef}>
        {!isScanning && (
          <div className="scanner-overlay">
            <p>Camera not started</p>
          </div>
        )}
      </div>

      <div className="scanner-controls">
        {!isScanning ? (
          <button 
            onClick={startScanning} 
            className="btn btn-primary btn-large"
          >
            📷 Start Camera
          </button>
        ) : (
          <button 
            onClick={stopScanning} 
            className="btn btn-secondary btn-large"
          >
            ⏸️ Stop Camera
          </button>
        )}
      </div>

      <div className="scanner-instructions">
        <p>💡 Position barcode within the camera view</p>
        {lastScan && (
          <p className="last-scan">Last scanned: {lastScan}</p>
        )}
      </div>
    </div>
  );
};

export default BarcodeScanner;
